var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"대령님.","JPN":"大佐。","ENG":"Colonel.","TWN":"上校。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GUARD_EXILER_NPC_NULL","text":{"KOREA":"으악!!","JPN":"うわあ！！","ENG":"Aaargh!","TWN":"啊啊！！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_MONSTER_HIT_SMALL"},{"id":"L7_1","type":"dialog","speaker":"GUARD_EXILER_NPC_NULL","text":{"KOREA":"쏴라! 마지막 순간까지 포기하지 마라!","JPN":"撃て！　最後の瞬間まで諦めるな！","ENG":"Pull the trigger! Don't give up until the very last second!","TWN":"開火！直到最後一刻也不要放棄！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_EXILER_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L10_1","type":"narration","speaker":null,"text":{"KOREA":"저, 대령님 말대로 최선을 다했어요.","JPN":"私、大佐の言葉を守って全力を尽くしてきました。","ENG":"Colonel, I did what you asked. I tried my best.","TWN":"我按照上校說的，用盡全力去做了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"narration","speaker":null,"text":{"KOREA":"마지막에, 마지막까지 포기하지 않고 여기까지 왔어요.","JPN":"最後の最後まで諦めずにここまで来ました。","ENG":"I didn't give up until the very last second, and I made it all the way here.","TWN":"直至最後也沒有放棄。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"카린 양! 지금이 기회에요!","JPN":"カリンさん！　今がチャンスです！","ENG":"Karin! Now's your chance!","TWN":"卡琳！趁現在！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L17_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"으아아아아아아아아아아아아앗!!","JPN":"うわあああああああああっ！！","ENG":"Aaaaaaaaaaargh!!","TWN":"呵啊啊啊啊啊啊啊！！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"narration","speaker":null,"text":{"KOREA":"그러니까, 최소한 제 마지막은……","JPN":"だから、せめて私の最後は……","ENG":"So, at least for my last moment...","TWN":"所以，至少在最後一刻……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"……크헉!!","JPN":"……くはっ！！","ENG":"...Kuh!!","TWN":"……呃！！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"카린 양! 괜찮아요!?","JPN":"カリンさん！　大丈夫ですか！？","ENG":"Karin! Are you okay?!","TWN":"卡琳！你沒事吧？！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"KING_EXILER_NULL_NULL","text":{"KOREA":"<color=#ff3636>그렇군.</color>","JPN":"<color=#ff3636>そうか。</color>","ENG":"<color=#ff3636>I see.</color>","TWN":"<color=#ff3636>看來。</color>"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BREATH_MASK"},{"id":"L25_1","type":"dialog","speaker":"KING_EXILER_NULL_NULL","text":{"KOREA":"<color=#ff3636>여기서 너희 둘을 죽여 놓지 않으면.</color>","JPN":"<color=#ff3636>ここでお前らを殺しておかなければ。</color>","ENG":"<color=#ff3636>If I don't eliminate you two right now...</color>","TWN":"<color=#ff3636>如果不在這裡殺了你們二個。</color>"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KING_EXILER_NULL_NULL","text":{"KOREA":"<color=#ff3636>너희 인간은 계속해서 이 몸의 업을 가로막겠지.</color>","JPN":"<color=#ff3636>お前ら人間は、いつまでも俺の仕事の邪魔してくるだろうな。</color>","ENG":"<color=#ff3636>You humans will keep trying to stop me.</color>","TWN":"<color=#ff3636>你們就會一直妨礙我。</color>"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"시끄러워, 침식체.","JPN":"うるさい、侵食体。","ENG":"Shut up, C.O.","TWN":"你閉嘴，侵蝕體。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"중얼거리지 말고 어서, 덤벼.","JPN":"ぶつぶつ言ってないで、早くかかって来な。","ENG":"Stop muttering to yourself and bring it!","TWN":"別廢話了，快點來吧！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"narration","speaker":null,"text":{"KOREA":"최소한 제 마지막은, 당신처럼 죽고 싶어요.","JPN":"最後だけは、あなたのような死に方をしたいんです。","ENG":"At least for my last moment, I want to die like you.","TWN":"至少，在最後一刻，我要像你一樣光榮地死去。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"narration","speaker":null,"text":{"KOREA":"대령님.","JPN":"大佐。","ENG":"Colonel.","TWN":"上校。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"카린 양? 카린 양! 카린 양……!!","JPN":"カリンさん？　カリンさん！　カリンさん……！！","ENG":"Karin? Karin! Karin...!!","TWN":"卡琳？卡琳！卡琳……！！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L40_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"갑자기 왜 끼어든 거예요! 죽고 싶어요!?","JPN":"どうしていきなり割り込んだんですか！　死にたいんですか！？","ENG":"Why are you intervening?! You wanna die or something?!","TWN":"為什麼突然擋過來！你想死嗎？！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"크윽, 시영 씨가 그걸 맞았으면……","JPN":"くっ、シノンさんがあれを食らったら……","ENG":"Kgh, but if you were hit by that, Shiyoung...","TWN":"咳，時雨你要是被擊中……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"결국엔…… 모두 죽었을 테니까요…….","JPN":"最後……全滅してしまいますから……","ENG":"Everyone... would've died...","TWN":"到最後……我們全部都會死掉……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"뭐라고요?","JPN":"え？","ENG":"What?","TWN":"你說什麼？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"알고 있었어요. 우리 중에는 시영 씨가 가장 강하니까…….","JPN":"わかっていました。私たちの中ではシノンさんが一番強いから……","ENG":"I know that you are the strongest out of all of us...","TWN":"我知道的。時雨是我們當中最強的……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"애초부터 가능성이 있던 건, 시영 씨뿐이었으니까…….","JPN":"そもそも可能性があったのは、シノンさんだけでしたから……","ENG":"You're the only one who has even a sliver of a chance to win, Shiyoung...","TWN":"從一開始有可能擊敗他的人，就只有你……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"시영 씨 검을 쥐세요…… 저도 여기서 지원 사격을……","JPN":"シノンさんナイフを取ってください……私もここから援護射撃を……","ENG":"Shiyoung, wield your blade... I'll provide support fire...","TWN":"時雨，把你的劍握好了……我在這裡用射擊支援你……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":" 윽!","JPN":" うっ！","ENG":"Ugh!","TWN":"呃！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그, 그렇지만! 카린 양, 눈이……!","JPN":"で、ですが！　カリンさん、目が……！","ENG":"B-but! Karin, your eye...!","TWN":"可，可是！卡琳，你的眼睛……！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KING_EXILER_NULL_NULL","text":{"KOREA":"재미있군.","JPN":"面白い。","ENG":"Interesting.","TWN":"有意思。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KING_EXILER_NULL_NULL","text":{"KOREA":"설마, 공간 째로 갑피를 절단하는 요행을 부릴 줄이야.","JPN":"まさか、空間ごと甲皮を切断する妙な技を繰り出すとは。","ENG":"I didn't expect anyone to cut through space to remove my armor.","TWN":"沒想到，你竟然能利用空間的力量傷到我的外殼。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"자, 잠깐? 당신은……?","JPN":"ま、まさか？　あなたは……？","ENG":"W-wait..! You're...","TWN":"等，等一下？你是……？"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KING_EXILER_NULL_NULL","text":{"KOREA":"기뻐해라, 인간.","JPN":"喜べ、人間。","ENG":"Rejoice, human.","TWN":"你要覺得榮幸，人類。"},"stage":{"bg":"EXILER_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KING_EXILER_NULL_NULL","text":{"KOREA":"이 몸의 갑피에 상처를 입힌 건, 이 세계에서 네가 처음이다.","JPN":"俺の甲皮に傷をつけたのは、この世界ではお前が初めてだ。","ENG":"You are the first in this world to make a dent in my armor.","TWN":"能傷到我外殼的，這個世界裡你是第一個。"},"stage":{"bg":"EXILER_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"어……?","JPN":"え……？","ENG":"Huh...?","TWN":"為……？"},"stage":{"bg":"EXILER_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"어째서……? 어째서 대령님이……?","JPN":"どうして……？　どうして大佐が……？","ENG":"Why...? Why is Colonel...?","TWN":"為什麼……為什麼上校……？"},"stage":{"bg":"EXILER_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L17_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"대령님은 분명 그 작전에서…….","JPN":"大佐は確かにあの作戦で……","ENG":"But during the operation, Colonel was...","TWN":"上校明明在那次作戰裡……"},"stage":{"bg":"EXILER_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"크로스로드에서 전사하셨을 텐데……?","JPN":"クロスロードで戦死されたはずじゃ……？","ENG":"He was KIA in Crossroads...","TWN":"在十字路口作戰時戰死了……？"},"stage":{"bg":"EXILER_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"……후후.","JPN":"……ふふ。","ENG":"...Ha ha.","TWN":"……哈哈。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"나라고 어째서 두렵지 않겠어?","JPN":"怖くないはずがない。","ENG":"Do you think I'm not terrified?","TWN":"你怎麼知道我不會害怕？"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"대령님?","JPN":"大佐？","ENG":"Colonel?","TWN":"上校？"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"하지만 그저 마지막 순간까지 포기하지 않고 최선을 다하고 싶을 뿐이야.","JPN":"だが、ただ最後の瞬間まで諦めず、全力を尽くしたいだけだ。","ENG":"I just want to do my best without giving up until it's over.","TWN":"但我只是想堅持到最後一刻，絕不放棄，盡力而為。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"사령관님…… 그리고 먼저 간 다른 대원들 보기에 부끄럽지 않게 말이지.","JPN":"司令官……そして、先に逝った隊員たちに恥ずかしくないようにな。","ENG":"So I won't be ashamed to see the commander... and the rest of our fallen comrades.","TWN":"我希望能夠無愧於司令官……以及其他犧牲的隊員。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"그러니까, 너도 긍지 높은 델타 세븐의 일원이라면…….","JPN":"だから、お前も誇り高きデルタセブンの一員であるなら……","ENG":"So, as a proud member of Delta Seven...","TWN":"所以，你若也是榮耀第七三角洲部隊的一員……"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"narration","speaker":null,"text":{"KOREA":"마지막 순간까지 포기하지 마, 카린.","JPN":"最後の瞬間まであきらめるな、カリン。","ENG":"Don't give up until it's over, Karin.","TWN":"那就堅持到最後，不要放棄，卡琳。"},"stage":{"bg":"BLACK","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"KING_EXILER_NULL_NULL","text":{"KOREA":"나는 증오스러운 나의 적을 죽이고 또 죽여서, 이 세계에서 모두 없애 버릴 것이다.","JPN":"俺は憎き敵であるネフィリムを殺して殺しまくって、この世界からすべて消し去ってみせる。","ENG":"I shall kill those despicable enemies as many times as needed and exterminate them from this world.","TWN":"我將令我憎惡的敵人殺了一遍又一遍，讓他們徹底消失於這個世界。"},"stage":{"bg":"EXILER_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"KING_EXILER_NULL_NULL","text":{"KOREA":"종극에는 그들의 피로써 이 세계를 군림하는 <color=#ffd34c>왕</color>이 되어주지.","JPN":"最終的には、やつらの血を糧にこの世界に君臨する<color=#ffd34c>王</color>になってやる。","ENG":"In the end, I shall rise as the <color=#ffd34c>king</color> of this world with their blood.","TWN":"最後，以他們的鮮血為基座，成為淩駕於這個世界的<color=#ffd34c>王</color>。"},"stage":{"bg":"EXILER_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그럼…….","JPN":"それじゃあ……","ENG":"Then...","TWN":"難道……"},"stage":{"bg":"EXILER_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"지금껏…… 아포리아가 네피림의 고치를 파괴했던 이유가 설마……?","JPN":"今まで……アポリアがネフィリムの繭を破壊して回っていたのは、まさか……？","ENG":"The reason... why Aporia has been destroying the Nephil cocoons is because...","TWN":"至今為止……阿波利亞破壞諾菲力繭的理由難道是……？"},"stage":{"bg":"EXILER_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"……이럴 수는 없어.","JPN":"……こんなはずない。","ENG":"...This can’t be real.","TWN":"……不可能。"},"stage":{"bg":"EXILER_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"거짓말이야……!! 이건 거짓말이라고……!!","JPN":"嘘……！！　こんなの嘘よ……！！","ENG":"You're lying...! This is all a lie...!","TWN":"騙人……！！這不是真的……！！"},"stage":{"bg":"EXILER_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L40_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"카린 양! 진정하세요!","JPN":"カリンさん！　落ち着いてください！","ENG":"Karin! Keep your head cool!","TWN":"卡琳！！冷靜一點！"},"stage":{"bg":"EXILER_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"KING_EXILER_NULL_NULL","text":{"KOREA":"하지만 이 몸의 업을 가로막는 이상, 모든 인간을 한 마리도 남김없이 죽여주지.","JPN":"だが、俺の仕事の邪魔をするというなら、人間は一人残らず皆殺しだ。","ENG":"But if you stop me from my duties, I shall obliterate all humans.","TWN":"既然你們如此礙事，那我便把人類也殺得乾乾淨淨，一個不留。"},"stage":{"bg":"EXILER_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"KING_EXILER_NULL_NULL","text":{"KOREA":"왜냐하면, 그건 이 몸의 결정 사항이니까.","JPN":"なぜなら、それは俺の決定事項だからだ。","ENG":"Because, that's what I've decided.","TWN":"至於為什麼……因為這是我決定的。"},"stage":{"bg":"EXILER_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_ELECTRIC_03"},{"id":"L45_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"온다! 카린 양! 피해야 해요!","JPN":"来ます！　カリンさん！　逃げてください！","ENG":"He's coming this way! Karin! Watch out!","TWN":"他過來了！卡琳！閃開！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"이러다간 정말로 죽는다고요! 빨리 일어나세요, 카린 양!","JPN":"このままじゃ本当に死んでしまいますよ！　早く起き上がってください、カリンさん！","ENG":"Quick! Get up, Karin! Or else you're really going to die!","TWN":"這樣下去真的會死！趕快站起來，卡琳！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L48_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"이제, 그만해요. 시영 씨…….","JPN":"もう、辞めましょう。シノンさん……","ENG":"I've had enough, Shiyoung...","TWN":"夠了，時雨……"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"네?","JPN":"はい？","ENG":"Huh?","TWN":"什麼？"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"저 사실, 알고 있었어요.","JPN":"実は私、わかっていたんです。","ENG":"In truth, I knew.","TWN":"我其實是知道的。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"아무리 노력해도, 결국 아무것도 바꿀 수 없다는 걸…….","JPN":"いくら努力しても、結局は何も変えられないってこと……","ENG":"That no matter how hard I try, nothing will change...","TWN":"不管再怎麼努力，也無法改變結局……"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"하지만 그럼에도…… 그럼에도 포기하지 않았어…….","JPN":"それでも……それでも諦めなかった……","ENG":"But despite it... I never gave up...","TWN":"不過就算這樣……我也沒有放棄……"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"짊어져야만 한다고…… 짊어질 수 있다고 생각했으니까……!","JPN":"背負うべきなんだと……背負えると思っていたから……！","ENG":"I thought I had to carry the weight... That I could endure it...!","TWN":"因為我覺得這是我應該背負的……我可以背負的……！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"하지만 이젠 지쳤어요……. 이제 더는 살아갈 자신이 없어…….","JPN":"でももう疲れました……もう生きていく自信がない……","ENG":"But I'm exhausted now... I have no more will to live...","TWN":"但現在我累了……已經沒有……活下去的勇氣了……"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그러니까……. 대령님.","JPN":"ですから……大佐。","ENG":"So... Colonel.","TWN":"所以……上校。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"차라리 여기서 저를……","JPN":"いっそここで私を……","ENG":"If you could just...","TWN":"乾脆就在這裡……"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_QM","text":{"KOREA":"한심해서 더는 못 봐주겠군.","JPN":"情けなくて目も当てられないな。","ENG":"Pathetic.","TWN":"真是可笑。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"안토…… 노프……?","JPN":"アント……ノフ……？","ENG":"Ant... onov...?","TWN":"安，安東諾夫……？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"꼴사납게 도망치지 않겠다고, 끝까지 싸우겠다고 했으면서.","JPN":"惨めに逃げたりしないと、最後まで戦うと言っておきながら。","ENG":"You said you would not run away like a coward. That you would fight until the end.","TWN":"我記得你說過，不想狼狽地逃跑，要奮戰到最後。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"결국 자네는 워커 대령님을 세계의 <color=#ffd34c>악</color>으로서 죽게 할 셈인가!","JPN":"結局君は、ウォーカー大佐を世界の<color=#ffd34c>悪</color>のままで、死なせるつもりか！","ENG":"Are you going to let Colonel Walker die as the <color=#ffd34c>villain</color> of this world?!","TWN":"結果，你卻乞求著要讓上校作為世界之<color=#ffd34c>惡</color>，殺死你嗎！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L21_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"악?","JPN":"悪？","ENG":"Villain?","TWN":"惡？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"인류를 위해 헌신한 영웅이 스스로의 의지와 관계없이 인류를 말살하는 것을.","JPN":"人類のために身を捧げた英雄が、自らの意思とは無関係に人類を抹殺しようとしているのに。","ENG":"A hero who sacrificed his life for this world is now attempting to annihilate mankind, regardless of his will.","TWN":"為人類獻身的英雄，結果卻喪失了意志，轉而扼殺人類。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"그 따위 한심한 이유만으로, 대령님을 저 상태로 내버려 둘 셈인가!","JPN":"そんな情けない理由で、大佐をあのままにしておくのか！","ENG":"Are you going to leave him like this because of a pathetic reason like that?!","TWN":"因為你那個可笑的理由，就任憑上校變成那副德性嗎！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"그러고도 자네는 스스로를 긍지 높은 델타 세븐의 일원이라고 떠들어댔던 건가!","JPN":"その程度で君は自らを誇り高きデルタセブンの一員であるなどとぬかしていたのか！","ENG":"How dare you claim yourself to be a proud member of Delta Seven!","TWN":"虧你還自稱是榮耀第七三角洲部隊的一員！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"뭐, 뭐라고?","JPN":"な、何ですって？","ENG":"W-what?","TWN":"什，什麼？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"그래, 자네가 하기 싫다면, 내가 처리해주지!","JPN":"まぁいい、君がやりたくないなら、私が代わりにやるまでだ！","ENG":"Very well. If you refuse to do it, I shall do it for you!","TWN":"很好，既然你不想做，那就由我來！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"레베카!! 이 자들을 당장 아이기스로 대피시키도록!","JPN":"レベッカ！！　この者たちをアイギスに避難させろ！","ENG":"Rebecca!! Evacuate them to Aegis immediately!","TWN":"蕾貝卡！！立刻帶這些傢伙去埃癸斯避難！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L31_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"아이기스 함은 현 시간부로 5분 뒤에 이면세계로 다이브, 그림자로부터 도망친다!","JPN":"アイギスは現時刻より5分後に裏世界にダイブし、シャドウから避難する！","ENG":"In 5 minutes from now, Aegis will dive into Counterside and flee from the Shadow!","TWN":"埃癸斯艦將在5分鐘後躍入異界，逃離暗影！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"뭐? 그럼, 마스터는 어쩌게!?","JPN":"え？　じゃあ、マスターはどうするんだよ！？","ENG":"What? But what about you, Master?!","TWN":"什麼？那大姊你怎麼辦？！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"어떤 세계에서든, 어떤 인과에서든 대령님은 반드시 영웅으로 남아야만 해!","JPN":"いかなる世界においても、いかなる因果の中であっても、大佐は必ず英雄であり続けなければならない！","ENG":"No matter what world it is, no matter the causality, Colonel must remain a hero!","TWN":"不論是在哪個世界，不論是何種因果，上校都必須是英雄！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"그렇지 않은 세계는 내가 용납할 수 없어!","JPN":"そうでない世界は、私が許さない！","ENG":"I shall not tolerate any world where he does not!","TWN":"若不是那樣的世界，我無法容忍！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L37_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"후후, 운명은 참 짓궂군요. 대령님.","JPN":"ふふ、運命とは実に皮肉なものですね。大佐。","ENG":"Ha ha, fate can be so cruel, Colonel.","TWN":"呵，真是造化弄人呢，上校。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L38_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"오랜 세월만에 재회인데 그런 모습이 되신 건 무척이나 안타깝습니다만…….","JPN":"こんなに久しぶりに再会したというのに、そのような姿になっておられて非常に残念ですが……","ENG":"It is a pity what happened to you, considering this is our first reunion in many years...","TWN":"時隔多年，再次重逢，卻是以這種樣子，真是非常的遺憾……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"narration","speaker":null,"text":{"KOREA":"어리석은 일이었다.","JPN":"愚かなことだった。","ENG":"I knew it was foolish of me.","TWN":"真是件愚蠢的事……"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"narration","speaker":null,"text":{"KOREA":"알고 있다. 우리의 사명을 달성하기 위해서라면 그냥 무시하는 게 맞았다.","JPN":"わかっていた。我々の使命を達成するためには、当然無視すべきだった。","ENG":"For our mission, it was best to just ignore it.","TWN":"我知道，為了完成我們的使命，我應該無視的。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"KING_EXILER_NULL_NULL","text":{"KOREA":"<color=#ff3636>너는, 이 세계의 인간이 아니군.</color>","JPN":"<color=#ff3636>お前は、この世界の人間じゃないな。</color>","ENG":"<color=#ff3636>You are not a human from this world.</color>","TWN":"<color=#ff3636>你不是這個世界的人。</color>"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"KING_EXILER_NULL_NULL","text":{"KOREA":"<color=#ff3636>너도 나를 방해할 셈인가?</color>","JPN":"<color=#ff3636>お前も俺の邪魔をするのか？</color>","ENG":"<color=#ff3636>Are you going to interfere as well?</color>","TWN":"<color=#ff3636>你也打算妨礙我嗎？</color>"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"narration","speaker":null,"text":{"KOREA":"하지만 그런 걸 따지기도 전에 몸이 먼저 튀어 나갔다.","JPN":"しかし、そんな是非を考える間もなく身体が先に動いた。","ENG":"But before I could think, my body was already reacting.","TWN":"但還沒來得及細想，身體就下意識做出了反應。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"narration","speaker":null,"text":{"KOREA":"대령님의 얼굴, 목소리…… 이젠 점점 흐릿해져 간다고 생각했는데…….","JPN":"大佐の顔、声……もう記憶が薄れていると思っていたのに……","ENG":"Colonel Walker... your face and your voice... I thought they were fading away in my memory...","TWN":"上校的臉龐、聲音……我本以為已經記不太清了……"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"narration","speaker":null,"text":{"KOREA":"전혀 아니었다.","JPN":"全くそうじゃなかった。","ENG":"But I was wrong.","TWN":"原來不是這樣。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"아이기스의 화력 지원 없이, 쇠약해진 이 육체로 과연 얼마나 버틸 수 있을까?","JPN":"アイギスの火力支援なしに、脆くなったこの肉体で、果たしてどれだけ持ちこたえられるか？","ENG":"I wonder how long my weakened body will last without the firepower support of Aegis.","TWN":"沒有埃癸斯的火力支援，這具虛弱的軀殼究竟可以支撐多久呢？"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"5종 침식체, 그것도 그림자가 되어버린 대령님을 내가 막을 수 있을까?","JPN":"第5種侵食体、しかもシャドウになってしまった大佐を、私は止められるんだろうか？","ENG":"Will I be able to stop a Category 5 C.O., the Shadow that was once Colonel?","TWN":"5類侵蝕體，我能阻擋住成為暗影的上校嗎？"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"아니. 막을 수 있는지, 없는지는 중요하지 않다.","JPN":"いや、止められるか、止められないかは重要じゃない。","ENG":"No. It does not matter whether I can or cannot.","TWN":"不，這並不重要。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"narration","speaker":null,"text":{"KOREA":"중요한 건.","JPN":"大事なのは。","ENG":"What matters is...","TWN":"重要的是。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"하지만 걱정하지 않으셔도 됩니다, 대령님.","JPN":"心配はいりません、大佐。","ENG":"However, there is nothing to worry about, Colonel.","TWN":"你可以放心了，上校。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_ENERGY_SMALL"},{"id":"L10_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"<color=#ffd34c>제</color>가 반드시 당신을 죽여드릴 테니까요.","JPN":"<color=#ffd34c>私</color>が必ずあなたを殺しますから。","ENG":"<color=#ffd34c>I</color> will give you eternal peace.","TWN":"因為，<color=#ffd34c>我</color>一定會殺了你。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};